function solve(n: number, edges: number[][]): number {
    // Build the graph: original edges and reversed edges (for switch usage)
    const graph: Map<number, [number, number, boolean][]> = new Map();
    const reversedEdges: Map<number, [number, number][]> = new Map();

    for (const [u, v, w] of edges) {
        if (!graph.has(u)) graph.set(u, []);
        graph.get(u)!.push([v, w, false]); // false indicates original edge

        if (!reversedEdges.has(v)) reversedEdges.set(v, []);
        reversedEdges.get(v)!.push([u, w]); // store for potential reversal
    }

    // Priority queue: [currentCost, node, hasUsedSwitch]
    const heap: [number, number, boolean][] = [];
    heap.push([0, 0, false]);

    // Visited: node -> min cost for [hasUsedSwitch: false, true]
    const visited: Map<number, [number, number]> = new Map();
    visited.set(0, [0, Infinity]);

    while (heap.length > 0) {
        heap.sort((a, b) => b[0] - a[0]); // Simple sort for priority queue (not optimal)
        const [currentCost, node, hasUsedSwitch] = heap.pop()!;

        if (node === n - 1) {
            return currentCost;
        }

        // Process original edges
        if (graph.has(node)) {
            for (const [neighbor, weight, _] of graph.get(node)!) {
                const newCost = currentCost + weight;
                const visitedEntry = visited.get(neighbor) || [Infinity, Infinity];
                if (!hasUsedSwitch && newCost < visitedEntry[0]) {
                    visited.set(neighbor, [newCost, visitedEntry[1]]);
                    heap.push([newCost, neighbor, hasUsedSwitch]);
                } else if (hasUsedSwitch && newCost < visitedEntry[1]) {
                    visited.set(neighbor, [visitedEntry[0], newCost]);
                    heap.push([newCost, neighbor, hasUsedSwitch]);
                }
            }
        }

        // Process reversed edges (if switch hasn't been used yet)
        if (!hasUsedSwitch && reversedEdges.has(node)) {
            for (const [neighbor, weight] of reversedEdges.get(node)!) {
                const newCost = currentCost + 2 * weight;
                const visitedEntry = visited.get(neighbor) || [Infinity, Infinity];
                if (newCost < visitedEntry[1]) {
